{
  "type": "DRAG_FILL",
  "data": {
    "challenges": [
      {
        "instruction": "Fill in the blanks using clues from the flashcards about Khayan Township's cultural heritage.",
        "codeTemplate": "Khayan Township is known for its _______ traditions and practices, which are influenced by _______ ethnic groups.",
        "options": [
          "diverse",
          "single",
          "multiple",
          "limited"
        ],
        "correctAnswer": "diverse,multiple",
        "explanation": "Khayan Township's cultural heritage is characterized by diverse traditions and practices from multiple ethnic groups."
      },
      {
        "instruction": "Complete the statement using information from the history of Yangon.",
        "codeTemplate": "The establishment of _______ was a significant event in the _______ of Myanmar.",
        "options": [
          "Yangon",
          "Mandalay",
          "Naypyidaw",
          "Bagan"
        ],
        "correctAnswer": "Yangon,history",
        "explanation": "Yangon, formerly known as Rangoon, plays a crucial role in the history of Myanmar."
      },
      {
        "instruction": "Use the flashcards to fill in the blanks about the communities in Khayan Township.",
        "codeTemplate": "The communities in Khayan Township contribute to its _______ and _______.",
        "options": [
          "diversity",
          "uniformity",
          "tradition",
          "isolation"
        ],
        "correctAnswer": "diversity,tradition",
        "explanation": "The communities in Khayan Township enhance its diversity and enrich its traditions."
      }
    ]
  }
}
